            IsPublished = true,
            SortOrder = 3,
            AppRoutes = """["/ai"]""",
            Tags = """["ai","reference"]""",
            ContentJson = """{"title":"AI Assistant Field Reference","groups":[{"heading":"Sidebar Elements","items":[{"label":"Assistant Card","value":"Displays icon, name, and description for each assistant. Click to select. The active assistant is highlighted with a visual indicator."},{"label":"Icon","value":"Material icon representing the assistant's domain (e.g., school for HR, shopping_cart for Procurement). Configured by admin."},{"label":"Name","value":"The assistant's display name (e.g., 'HR Assistant', 'Sales Advisor'). Set by admin in AI Assistants settings."},{"label":"Description","value":"Short summary of what the assistant specializes in. Shown on the card and in the welcome screen."},{"label":"Active Indicator","value":"Visual highlight on the currently selected assistant card. Only one assistant is active at a time."}]},{"heading":"Chat Area — Welcome Screen","items":[{"label":"Assistant Icon (large)","value":"Prominent display of the selected assistant's icon, shown centered above the name."},{"label":"Assistant Name","value":"Large heading showing which assistant you're chatting with."},{"label":"Assistant Description","value":"Full description of the assistant's capabilities and focus area."},{"label":"Starter Questions Grid","value":"Grid of clickable question cards. Each assistant has its own set of starter questions configured by admin. Clicking one sends it as the first message."}]},{"heading":"Chat Area — Message Thread","items":[{"label":"User Messages","value":"Right-aligned bubbles showing your sent messages. Displayed with your initials/avatar."},{"label":"Assistant Messages","value":"Left-aligned bubbles with the assistant's avatar and icon. May contain formatted text, lists, and code blocks."},{"label":"Typing Indicator","value":"Three animated dots shown while the assistant is generating a response. Appears in the assistant's message area."},{"label":"Message History","value":"Scrollable thread of all messages in the current conversation. Last 10 messages are sent as context to the API for each new question."}]},{"heading":"Buttons and Actions","items":[{"label":"Send (send icon)","value":"Sends the current message to the assistant. Disabled when input is empty or while a response is being generated. Keyboard shortcut: Enter."},{"label":"Clear Chat (delete_sweep icon)","value":"Clears all messages for the current assistant and returns to the welcome screen. Disabled when there are no messages. Does not affect other assistants' conversations."},{"label":"Starter Question (card click)","value":"Sends the selected starter question as your first message, beginning the conversation."},{"label":"Assistant Card (sidebar click)","value":"Switches to the selected assistant. Your previous conversation with each assistant is preserved in memory for the session."}]},{"heading":"Input Behavior","items":[{"label":"Text Input","value":"Multi-line text field. Placeholder: 'Ask {assistantName}' where {assistantName} is the current assistant's name."},{"label":"Enter","value":"Sends the message (equivalent to clicking Send)."},{"label":"Shift+Enter","value":"Inserts a new line without sending. Use for multi-line questions."},{"label":"Empty Input","value":"Send button is disabled. You cannot send an empty message."},{"label":"While Sending","value":"Send button is disabled and shows a loading state until the assistant responds."}]},{"heading":"Data and API","items":[{"label":"Assistant List","value":"Loaded from GET /api/v1/ai/assistants. Returns AiAssistantListItem objects with id, name, description, icon, color, category, starterQuestions, and isActive flag."},{"label":"Chat Request","value":"POST /api/v1/ai/assistants/{id}/chat with body {text, history[]}. History includes the last 10 messages for context."},{"label":"Conversation Storage","value":"In-memory only (not persisted). Each assistant has its own conversation. Closing the browser or refreshing the page clears all conversations."},{"label":"Route","value":"/ai/{assistantId} — the selected assistant ID is in the URL, making it shareable/bookmarkable."}]}]}"""
