            Tags = """["ai","admin","assistant","configuration","walkthrough"]""",
            ContentJson = """{"appRoute":"/admin/ai-assistants","startButtonLabel":"Tour AI Assistant Setup","steps":[{"element":".panel-header","popover":{"title":"AI Assistants Panel","description":"This is the admin home for AI assistants, at Admin → AI Assistants. The header shows how many assistants exist. Every assistant configured here appears on the /ai page for users (when active). Admins only — this tab is not visible to regular users.","side":"bottom"}},{"element":".action-btn--create","popover":{"title":"New Assistant","description":"Click 'New Assistant' to open the assistant editor dialog. The same dialog opens when you click an existing row to edit it. We'll walk through every field in the dialog next.","side":"left"}},{"element":"app-data-table","popover":{"title":"The Assistants List","description":"Each row shows the assistant's colored icon, name (built-in assistants carry a 'Built In' chip), category, how many entity-type filters are set ('All' when none), and active status. Click any row to edit it. Built-in assistants can be edited but not deleted; custom assistants you create show a delete action.","side":"top"}},{"element":"app-data-table","popover":{"title":"Identity: Name, Category, Description, Icon, Color","description":"In the editor dialog, the top fields define how the assistant appears to users. Name and Category are required. Category is one of General, HR, Procurement, Sales, or Custom — the /ai page resolves the 'general' route to the assistant whose category is General. Description shows on the assistant card and welcome screen. Icon (a Material icon name) and Color set the visual identity; a live preview renders the icon in the chosen color.","side":"top"}},{"element":"app-data-table","popover":{"title":"System Prompt — the assistant's behavior","description":"The System Prompt (required, up to 50,000 characters) is the instruction that shapes how the assistant answers — its persona, tone, domain focus, and any rules. This is where you tell an HR assistant to answer as an HR specialist, or a Procurement assistant to focus on sourcing and POs. Users never see the system prompt; it runs behind every answer.","side":"top"}},{"element":"app-data-table","popover":{"title":"Allowed Entity Types — RAG grounding scope","description":"The Entity Type Filters multi-select scopes which of your indexed records the assistant may draw on when answering (RAG grounding). Leave it empty to allow ALL entity types (the list shows 'All'); or pick specific types — Job, Part, Customer, Vendor, Lead, Quote, Sales Order, Purchase Order, Invoice, and more — to keep, say, an HR assistant grounded only in employee data. This is how you keep each assistant focused and prevent it from answering from data outside its lane.","side":"top"}},{"element":"app-data-table","popover":{"title":"Starter Questions","description":"Add the suggested questions that appear on the assistant's welcome screen. Type a question, click Add, and it joins the list; remove any with the X. These are the clickable prompts users see before they've typed anything — give each assistant a few good entry-point questions for its domain.","side":"top"}},{"element":"app-data-table","popover":{"title":"Active, Sort Order, and Advanced","description":"The Active toggle controls whether users see this assistant on the /ai page — turn it off to retire an assistant without deleting it. Sort Order sets its position in the sidebar list. Under 'Advanced Settings' you can tune Temperature (0–1, answer creativity) and Max Context Chunks (1–20, how much retrieved data the assistant considers) — leave the defaults unless you have a reason to change them. Save commits the assistant; it appears for users immediately.","side":"top"}}]}"""
        });

        // ── Advanced Reference (Reference) ───────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "AI Assistant — Advanced Reference",
